     1→/**
     2→ * MMS Service Demand Service
     3→ *
     4→ * Manages fleet availability requirements - a CRITICAL v2.1 service.
     5→ * Service demand is a HARD CONSTRAINT for the optimizer: schedules that
     6→ * violate minimum train availability must be rejected.
     7→ *
     8→ * Key responsibilities:
     9→ * - Define minimum train requirements by fleet, day type, and time period
    10→ * - Validate that proposed PM schedules don't violate availability
    11→ * - Calculate default demand (85% of fleet) when no explicit config exists
    12→ * - Support peak period requirements (AM, midday, PM, evening)
    13→ *
    14→ * Business rules:
    15→ * - Optimizer CANNOT schedule PM that would drop fleet below minTrainsRequired
    16→ * - Day types: WEEKDAY, SATURDAY, SUNDAY, HOLIDAY
    17→ * - Demand records are versioned by effectiveDate (most recent applies)
    18→ * - Peak period requirements are optional but enforced if defined
    19→ *
    20→ * @see specs/003-database-schema.md Section 3.2.1 (Service Demand)
    21→ * @see specs/004-domain-services.md Section 4.2.6 (Service Demand Service)
    22→ */
    23→
    24→import { eq, and, sql, desc, lte, count, inArray, gte } from 'drizzle-orm';
    25→import type { SQL } from 'drizzle-orm';
    26→import { BaseService, MmsAttributes } from '../lib/services/base';
    27→import {
    28→  serviceDemand,
    29→  trains,
    30→  fleets,
    31→  pmSchedule,
    32→  type ServiceDemand,
    33→  type NewServiceDemand,
    34→} from '../lib/db/schema';
    35→import {
    36→  NotFoundError,
    37→  ValidationError,
    38→  DuplicateError,
    39→} from '../lib/errors';
    40→
    41→// =============================================================================
    42→// Types
    43→// =============================================================================
    44→
    45→/** Day type enum values */
    46→export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
    47→
    48→/** Time period for peak requirements */
    49→export type TimePeriod = 'PEAK_AM' | 'MIDDAY' | 'PEAK_PM' | 'EVENING' | 'ALL_DAY';
    50→
    51→/** Demand configuration for a specific fleet/date */
    52→export interface DemandConfig {
    53→  fleetId: string;
    54→  fleetCode: string;
    55→  date: string;
    56→  dayType: DayType;
    57→  minTrainsRequired: number;
    58→  standbyBuffer: number;
    59→  totalRequired: number; // minTrainsRequired + standbyBuffer
    60→  peakAmRequirement: number | null;
    61→  middayRequirement: number | null;
    62→  peakPmRequirement: number | null;
    63→  eveningRequirement: number | null;
    64→  source: 'CONFIG' | 'DEFAULT';
    65→  sourceRecord: ServiceDemand | null;
    66→}
    67→
    68→/** Availability validation result */
    69→export interface AvailabilityValidation {
    70→  isValid: boolean;
    71→  fleetId: string;
    72→  date: string;
    73→  dayType: DayType;
    74→  totalTrains: number;
    75→  fitTrains: number;
    76→  unavailableTrains: number;
    77→  inMaintenanceTrains: number;
    78→  additionalUnavailable: number;
    79→  availableTrains: number;
    80→  required: number;
    81→  surplus: number; // Positive = OK, Negative = VIOLATION
    82→  severity: 'OK' | 'WARNING' | 'VIOLATION';
    83→  message: string;
    84→}
    85→
    86→/** Violation detected for proposed PM */
    87→export interface DemandViolation {
    88→  date: string;
    89→  dayType: DayType;
    90→  trainId: string;
    91→  trainNumber: string;
    92→  pmCode: string;
    93→  required: number;
    94→  available: number;
    95→  shortfall: number;
    96→  severity: 'HARD' | 'SOFT';
    97→  message: string;
    98→}
    99→
   100→/** Proposed PM for violation checking */
   101→export interface ProposedPM {
   102→  trainId: string;
   103→  targetDate: string;
   104→  pmTypeId?: string;
   105→  pmCode?: string;
   106→  durationDays?: number;
   107→}
   108→
   109→/** Create demand request */
   110→export interface CreateDemandRequest {
   111→  fleetId: string;
   112→  effectiveDate: string;
   113→  dayType: DayType;
   114→  minTrainsRequired: number;
   115→  peakAmRequirement?: number;
   116→  middayRequirement?: number;
   117→  peakPmRequirement?: number;
   118→  eveningRequirement?: number;
   119→  standbyBuffer?: number;
   120→  source?: string;
   121→  notes?: string;
   122→  createdBy?: string;
   123→}
   124→
   125→/** Query filters for listing demand records */
   126→export interface DemandListFilters {
   127→  fleetId?: string;
   128→  dayType?: DayType | DayType[];
   129→  effectiveDateFrom?: string;
   130→  effectiveDateTo?: string;
   131→}
   132→
   133→/** Fleet availability summary */
   134→export interface FleetAvailabilitySummary {
   135→  fleetId: string;
   136→  fleetCode: string;
   137→  totalTrains: number;
   138→  fitTrains: number;
   139→  restrictedTrains: number;
   140→  groundedTrains: number;
   141→  inMaintenanceTrains: number;
   142→  availableTrains: number;
   143→  demandConfig: DemandConfig;
   144→  utilizationPct: number;
   145→  status: 'OK' | 'WARNING' | 'CRITICAL';
   146→}
   147→
   148→// =============================================================================
   149→// Constants
   150→// =============================================================================
   151→
   152→/** Default fleet availability percentage when no config exists */
   153→const DEFAULT_AVAILABILITY_PCT = 0.85;
   154→
   155→/** Default standby buffer */
   156→const DEFAULT_STANDBY_BUFFER = 2;
   157→
   158→/** Warning threshold: < this % surplus triggers warning */
   159→const WARNING_THRESHOLD_PCT = 0.10;
   160→
   161→// =============================================================================
   162→// Service Demand Service
   163→// =============================================================================
   164→
   165→export class ServiceDemandService extends BaseService {
   166→  constructor() {
   167→    super({ name: 'service-demand-service', version: '1.0.0' });
   168→  }
   169→
   170→  // ===========================================================================
   171→  // Demand Configuration
   172→  // ===========================================================================
   173→
   174→  /**
   175→   * Get demand configuration for a fleet on a specific date.
   176→   *
   177→   * This is the primary method for the optimizer to determine minimum
   178→   * train requirements. It:
   179→   * 1. Determines the day type for the date
   180→   * 2. Finds the most recent effective demand config
   181→   * 3. Falls back to 85% of fleet size if no config exists
   182→   *
   183→   * @param fleetId - Fleet to get demand for
   184→   * @param targetDate - Date to check (YYYY-MM-DD)
   185→   * @param holidays - Optional array of holiday dates (YYYY-MM-DD)
   186→   * @returns Demand configuration for the date
   187→   */
   188→  async getDemand(
   189→    fleetId: string,
   190→    targetDate: string,
   191→    holidays?: string[]
   192→  ): Promise<DemandConfig> {
   193→    return this.traced('getDemand', async (span) => {
   194→      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
   195→      span.setAttribute('demand.targetDate', targetDate);
   196→
   197→      // Verify fleet exists
   198→      const fleet = await this.db.query.fleets.findFirst({
   199→        where: eq(fleets.id, fleetId),
   200→      });
   201→
   202→      if (!fleet) {
   203→        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
   204→          entityType: 'fleet',
   205→          entityId: fleetId,
   206→        });
   207→      }
   208→
   209→      // Determine day type
   210→      const dayType = this.getDayType(targetDate, holidays);
   211→      span.setAttribute('demand.dayType', dayType);
   212→
   213→      // Find most recent effective demand config
   214→      const demandRecord = await this.db.query.serviceDemand.findFirst({
   215→        where: and(
   216→          eq(serviceDemand.fleetId, fleetId),
   217→          eq(serviceDemand.dayType, dayType),
   218→          lte(serviceDemand.effectiveDate, targetDate)
   219→        ),
   220→        orderBy: desc(serviceDemand.effectiveDate),
   221→      });
   222→
   223→      if (demandRecord) {
   224→        span.setAttribute('demand.source', 'CONFIG');
