  2254→## 4.5 Strategic Planner
  2255→
  2256→### 4.5.1 Purpose
  2257→
  2258→Generate and maintain the 1-10 year strategic plan using genetic algorithms, constrained by capacity envelopes from the tactical model.
  2259→
  2260→### 4.5.2 Implementation
  2261→
  2262→```typescript
  2263→interface StrategicPlannerConfig {
  2264→  horizonYears: number;          // 10
  2265→  granularity: 'MONTHLY' | 'QUARTERLY';
  2266→  populationSize: number;        // 100
  2267→  generations: number;           // 500
  2268→  mutationRate: number;          // 0.1
  2269→  eliteCount: number;            // 10
  2270→}
  2271→
  2272→interface StrategicAllocation {
  2273→  trainId: string;
  2274→  pmTypeId: string;
  2275→  targetQuarter: string;  // e.g., '2028-Q2'
  2276→  estimatedHours: number;
  2277→  estimatedCost: number;
  2278→}
  2279→
  2280→class StrategicPlanner {
  2281→  private constraintAggregation: ConstraintAggregationService;
  2282→  
  2283→  async generatePlan(
  2284→    fromBaseline: string | null
  2285→  ): Promise<StrategicPlanResult> {
  2286→    // 1. Load current fleet state
  2287→    const fleetState = await this.getFleetState();
  2288→    
  2289→    // 2. Project PM requirements for each train
  2290→    const pmRequirements = await this.projectPMRequirements(
  2291→      fleetState,
  2292→      this.config.horizonYears
  2293→    );
  2294→    
  2295→    // 3. Generate constraint envelopes for each quarter
  2296→    const envelopes = await this.generateEnvelopes();
  2297→    
  2298→    // 4. Run genetic algorithm
  2299→    const bestPlan = await this.runGeneticAlgorithm(
  2300→      pmRequirements,
  2301→      envelopes
  2302→    );
  2303→    
  2304→    // 5. Validate against constraint envelopes
  2305→    const validation = await this.validatePlan(bestPlan, envelopes);
  2306→    
  2307→    if (!validation.valid) {
  2308→      // Attempt repair
  2309→      const repairedPlan = await this.repairPlan(bestPlan, validation);
  2310→      return {
  2311→        plan: repairedPlan,
  2312→        validation: await this.validatePlan(repairedPlan, envelopes),
  2313→        metrics: this.calculateMetrics(repairedPlan)
  2314→      };
  2315→    }
  2316→    
  2317→    return {
  2318→      plan: bestPlan,
  2319→      validation,
  2320→      metrics: this.calculateMetrics(bestPlan)
  2321→    };
  2322→  }
  2323→  
  2324→  /**
  2325→   * Project PM requirements for all trains over the planning horizon.
  2326→   * 
  2327→   * CRITICAL: This implementation correctly handles:
  2328→   * 1. PM hierarchy (C4 satisfies C1/C2/C3 - resets their counters)
  2329→   * 2. Dual triggers (mileage OR time, whichever comes first)
  2330→   * 3. Recent velocity calculation for accurate projections
  2331→   * 4. Cascading projections (each PM feeds into next cycle)
  2332→   */
  2333→  private async projectPMRequirements(
  2334→    fleetState: FleetState,
  2335→    horizonYears: number
  2336→  ): Promise<PMRequirement[]> {
  2337→    const requirements: PMRequirement[] = [];
  2338→    const horizonEnd = addYears(new Date(), horizonYears);
  2339→    
  2340→    for (const train of fleetState.trains) {
