  3003→## 4.7 Baseline Service
  3004→
  3005→### 4.7.1 Purpose
  3006→
  3007→Manage published plan baselines for drift analysis and scenario comparison.
  3008→
  3009→### 4.7.2 Implementation
  3010→
  3011→```typescript
  3012→class BaselineService {
  3013→  async publishBaseline(
  3014→    name: string,
  3015→    description: string,
  3016→    userId: string
  3017→  ): Promise<PlanBaseline> {
  3018→    // 1. Validate current plan has no critical conflicts
  3019→    const validation = await this.validatePlanForPublishing();
  3020→    if (!validation.valid) {
  3021→      throw new ValidationError(
  3022→        'Cannot publish baseline with critical conflicts',
  3023→        validation.conflicts
  3024→      );
  3025→    }
  3026→    
  3027→    // 2. Generate version number
  3028→    const latestBaseline = await this.getLatestBaseline();
  3029→    const version = this.incrementVersion(latestBaseline?.version || 'v0.0');
  3030→    
  3031→    // 3. Create baseline record
  3032→    const baseline = await this.db.transaction(async (tx) => {
  3033→      // Create baseline
  3034→      const [baselineRecord] = await tx.insert(planBaselines)
  3035→        .values({
  3036→          name,
  3037→          description,
  3038→          version,
  3039→          baselineDate: new Date(),
  3040→          horizonEnd: addYears(new Date(), 10),
  3041→          status: 'PUBLISHED',
  3042→          createdBy: userId,
  3043→          publishedBy: userId,
  3044→          publishedAt: new Date(),
  3045→          fleetCount: await this.getActiveTrainCount(),
  3046→          totalPmScheduled: await this.getScheduledPMCount(),
  3047→          totalManhoursProjected: await this.getTotalProjectedHours()
  3048→        })
  3049→        .returning();
  3050→      
  3051→      // Snapshot PM schedule
  3052→      await tx.execute(sql`
  3053→        INSERT INTO baseline_pm_schedule 
  3054→          (baseline_id, train_id, pm_type_id, projected_date, projected_mileage_km, assigned_depot_id, assigned_hours)
  3055→        SELECT 
  3056→          ${baselineRecord.id},
  3057→          train_id,
  3058→          pm_type_id,
  3059→          target_date,
  3060→          target_mileage_km,
  3061→          assigned_depot_id,
  3062→          assigned_hours
  3063→        FROM pm_schedule
  3064→        WHERE scenario_id IS NULL
  3065→          AND status IN ('SCHEDULED', 'IN_PROGRESS')
  3066→          AND target_date >= CURRENT_DATE
  3067→      `);
  3068→      
  3069→      // Snapshot mileage projections
  3070→      const projections = await this.generateMileageProjections(
  3071→        baselineRecord.horizonEnd
  3072→      );
  3073→      
  3074→      for (const proj of projections) {
  3075→        await tx.insert(baselineMileageProjection)
  3076→          .values({
  3077→            baselineId: baselineRecord.id,
  3078→            trainId: proj.trainId,
  3079→            projectionDate: proj.date,
  3080→            projectedCumulativeKm: proj.projectedKm,
  3081→            dailyRateKm: proj.dailyRate
  3082→          });
  3083→      }
  3084→      
  3085→      // Supersede previous baseline
  3086→      if (latestBaseline) {
  3087→        await tx.update(planBaselines)
  3088→          .set({
  3089→            status: 'SUPERSEDED',
  3090→            supersededBy: baselineRecord.id,
  3091→            supersededAt: new Date()
  3092→          })
  3093→          .where(eq(planBaselines.id, latestBaseline.id));
  3094→      }
  3095→      
  3096→      return baselineRecord;
  3097→    });
  3098→    
  3099→    // 4. Audit log
  3100→    await this.auditLog.record({
  3101→      entityType: 'plan_baseline',
  3102→      entityId: baseline.id,
  3103→      action: 'PUBLISH',
  3104→      userId,
  3105→      newValues: { name, version, description }
  3106→    });
  3107→    
  3108→    // 5. Notify
  3109→    await this.notificationService.notify({
  3110→      type: 'BASELINE_PUBLISHED',
  3111→      title: `New baseline published: ${version}`,
  3112→      body: description,
  3113→      recipients: await this.getPlannerUserIds()
  3114→    });
  3115→    
  3116→    return baseline;
  3117→  }
  3118→  
  3119→  private async generateMileageProjections(
  3120→    horizonEnd: Date
  3121→  ): Promise<MileageProjection[]> {
  3122→    const trains = await this.db.query.trains.findMany({
  3123→      where: eq(trains.active, true)
  3124→    });
  3125→    
  3126→    const projections: MileageProjection[] = [];
  3127→    
  3128→    for (const train of trains) {
  3129→      // Calculate average daily mileage from last 30 days
  3130→      const recentMileage = await this.db.query.mileageReadings.findMany({
  3131→        where: and(
